class Solution:
    def singleNumber(self, nums: list[int]) -> int:
        result = 0

        # Iterate over all 32 bits of an integer
        # (assuming 32-bit signed integers, which is typical for such problems)
        for i in range(32):
            bit_sum = 0
            # For each bit position, sum up the corresponding bit from all numbers
            for num in nums:
                # Check if the i-th bit is set in the current number
                if (num >> i) & 1:
                    bit_sum += 1

            # If the sum of the i-th bits modulo 3 is 1, it means the unique number has this bit set
            if bit_sum % 3 == 1:
                result |= (1 << i)

        # Handle potential negative unique numbers
        # If the 31st bit (0-indexed) is set, it indicates a negative number
        # in a 32-bit two's complement representation.
        # Python stores integers with arbitrary precision, so 'result' might be a large positive number
        # if the unique number was negative. We need to convert it to its 32-bit signed equivalent.
        if (result >> 31) & 1:
            result -= (1 << 32)

        return result
